        --max-records "$MAX_RECORDS" \
        --marker "$MARKER"
}


# describe-service-updates: Returns details of the service updates.

    Parameters:
        service_update_name (Optional[str]): The unique ID of the service update to describe.
        service_update_status (Optional[List[str]]): List of status values to filter by.
            Valid values: available | cancelled | expired | complete
        starting_token (Optional[str]): An optional token returned from a previous request.
            Use this token for pagination of results from this operation.
        page_size (Optional[int]): The maximum number of records to include in each page
            of results.
        max_items (Optional[int]): The maximum number of records to include in the response.
            If more records exist than the specified MaxItems value, a marker is included
            in the response so that the remaining results can be retrieved.

    Returns:
        Dict containing information about the service updates, including:
        - ServiceUpdates: List of service updates
        - NextToken: Token for next set of results
    
# Usage: describe-service-updates <service_update_name> <service_update_status> <starting_token> <page_size> <max_items>
describe-service-updates() {
    aws elasticache describe-service-updates \
        --service-update-name "$SERVICE_UPDATE_NAME" \
        --service-update-status "$SERVICE_UPDATE_STATUS" \
        --marker "$STARTING_TOKEN" \
        --max-records "$PAGE_SIZE" \
        --max-items "$MAX_ITEMS"
}


# delete-serverless-cache: Delete an Amazon ElastiCache serverless cache.

    This tool deletes a specified serverless cache from your AWS account.
    The cache must exist and be in a deletable state.

    Parameters:
        serverless_cache_name (str): Name of the serverless cache to delete.
        final_snapshot_name (Optional[str]): Name of the final snapshot to create before deletion.

    Returns:
        Dict containing the deletion response or error information.
    
# Usage: delete-serverless-cache <serverless_cache_name> <final_snapshot_name>
delete-serverless-cache() {
    aws elasticache delete-serverless-cache \
        --serverless-cache-name "$SERVERLESS_CACHE_NAME" \
        --final-snapshot-name "$FINAL_SNAPSHOT_NAME"
}


# describe-serverless-caches: Describe Amazon ElastiCache serverless caches in your AWS account.

    This tool retrieves detailed information about serverless caches including:
    - Cache configuration
    - Cache endpoints
    - Cache status
    - Cache size
    - Cache connections

    Parameters:
        serverless_cache_name (Optional[str]): Name of the serverless cache to describe. If not provided, describes all caches.
        max_items (Optional[int]): Maximum number of results to return.
        starting_token (Optional[str]): Token to start the list from a specific page.
        page_size (Optional[int]): Number of records to include in each page.

    Returns:
        Dict containing information about the serverless cache(s).
    
# Usage: describe-serverless-caches <serverless_cache_name> <max_items> <starting_token> <page_size>
describe-serverless-caches() {
    aws elasticache describe-serverless-caches \
        --serverless-cache-name "$SERVERLESS_CACHE_NAME" \
        --max-results "$MAX_ITEMS" \
        --next-token "$STARTING_TOKEN" \
        --max-records "$PAGE_SIZE"
}


# modify-serverless-cache: Modify an Amazon ElastiCache serverless cache.

    This tool modifies the configuration of an existing serverless cache including:
    - Cache description
    - Engine version
    - Snapshot settings
    - Usage limits
    - Security groups
    - User groups

    Parameters:
        serverless_cache_name (str): Name of the serverless cache to modify.
        apply_immediately (Optional[bool]): Whether to apply changes immediately or during maintenance window.
        description (Optional[str]): New description for the cache.
        major_engine_version (Optional[str]): New major engine version.
        snapshot_retention_limit (Optional[int]): Number of days for which ElastiCache retains automatic snapshots.
        daily_snapshot_time (Optional[str]): Time range (in UTC) when daily snapshots are taken (e.g., '04:00-05:00').
        cache_usage_limits (Optional[CacheUsageLimits]): New usage limits for the cache. Structure:
            {
                "DataStorage": {
                    "Maximum": int,  # Maximum storage in GB
                    "Minimum": int,  # Minimum storage in GB
                    "Unit": "GB"     # Storage unit (currently only GB is supported)
                },
                "ECPUPerSecond": {
                    "Maximum": int,  # Maximum ECPU per second
                    "Minimum": int   # Minimum ECPU per second
                }
            }
        security_group_ids (Optional[List[str]]): List of security group IDs.
        user_group_id (Optional[str]): ID of the user group to associate with the cache.

    Returns:
        Dict containing information about the modified serverless cache.
    
# Usage: modify-serverless-cache <request>
modify-serverless-cache() {
    aws elasticache modify-serverless-cache \
        --serverless-cache-name "$REQUEST"
}


# create-jump-host-serverless-cache: Creates an EC2 jump host instance to access an ElastiCache serverless cache via SSH tunnel.

    Args:
        serverless_cache_name (str): Name of the ElastiCache serverless cache to connect to
        key_name (str): Name of the EC2 key pair to use for SSH access
        subnet_id (str, optional): ID of the subnet to launch the EC2 instance in (must be public).
            If not provided and serverless cache uses default VPC, will auto-select a default subnet.
        security_group_id (str, optional): ID of the security group to assign to the EC2 instance.
            If not provided and serverless cache uses default VPC, will use the default security group.
        instance_type (str, optional): EC2 instance type. Defaults to "t3.small"

    Returns:
        Dict[str, Any]: Dictionary containing the created EC2 instance details

    Raises:
        ValueError: If subnet is not public or VPC compatibility check fails
    
# Usage: create-jump-host-serverless-cache <serverless_cache_name> <key_name> <subnet_id> <security_group_id> <instance_type>
create-jump-host-serverless-cache() {
    aws ec2 run-instances \
        --key-name "$KEY_NAME" \
        --subnet-id "$SUBNET_ID" \
        --security-group-ids "$SECURITY_GROUP_ID" \
        --instance-type "$INSTANCE_TYPE"
}


